  # Group triples by their subject to avoid repeating the subject in every clause.
      from collections import defaultdict
      subject_groups = defaultdict(list)
      for t in triples:
          subject_groups[t.subject].append(t)

      # Helper to clean quoted objects (used throughout the function)
      def clean_obj(o: str) -> str:
          return o.strip('"').strip("'")

      # Build helper maps for cross‑subject relations (e.g., country → leader)
      country_of = {}
      leader_of = {}
      for t in triples:
          if t.predicate == "country":
              country_of[t.subject] = clean_obj(t.object)
          elif t.predicate == "leader":
              leader_of[t.subject] = clean_obj(t.object)
